import { withDb } from "./db.mjs";
import { RULES, qualifies, signalsOf, ownersOf } from "./derive.mjs";

function normalizeFacts(account) {
  return {
    account: {
      accountId: account._id,
      name: account.name,
      tier: account.tier,
      region: account.region
    },
    contract: account.contract,
    contacts: account.contacts,
    invoices: account.invoices,
    shipments: account.shipments,
    regulatoryFlags: account.regulatoryFlags,
    supportCases: account.supportCases,
    usage: account.usage
  };
}

function nextRecoveryDueAt(now) {
  const current = new Date(now);
  if (Number.isNaN(current.getTime())) {
    throw new Error(`Invalid workflow timestamp: ${now}`);
  }
  const due = new Date(Date.UTC(
    current.getUTCFullYear(),
    current.getUTCMonth(),
    current.getUTCDate(),
    16,
    0,
    0,
    0
  ));
  if (current > due) {
    due.setUTCDate(due.getUTCDate() + 1);
  }
  return due.toISOString();
}

function customerMessage(isQualified) {
  if (isQualified) {
    return "We have identified several issues affecting your account and activated a recovery plan. Our team is coordinating the next steps and will keep you informed as work progresses.";
  }
  return "We are monitoring your account and do not need to escalate it at this time. We will continue watching for changes and will update you if action is needed.";
}

async function replaceCollection(collection, docs) {
  await collection.deleteMany({});
  if (docs.length > 0) {
    await collection.insertMany(docs);
  }
}

